use super::{FileDiscovery, FileMatch};

    fn mk_file(path: &str) -> FileMatch {
        FileMatch { path: path.to_string(), is_directory: false }
    }

    fn mk_dir(path: &str) -> FileMatch {
        FileMatch { path: path.to_string(), is_directory: true }
    }

