    #[test]
    fn file_match_icon_file() {
        let m = mk_file("src/main.rs");
        assert_eq!(m.icon(), "📄");
    }

    #[test]
    fn file_match_icon_directory() {
        let m = mk_dir("src/tui/");
        assert_eq!(m.icon(), "📁");
    }

    #[test]
    fn file_match_display() {
        let m = mk_file("src/main.rs");
        assert_eq!(m.display(), "📄 src/main.rs");
    }

    #[test]
    fn file_match_display_directory() {
        let m = mk_dir("src/tui/");
        assert_eq!(m.display(), "📁 src/tui/");
    }

