    #[test]
    fn fuzzy_match_empty_query_returns_all() {
        let entries = vec![mk_file("a.rs"), mk_file("b.txt"), mk_file("c.py")];
        let results = FileDiscovery::fuzzy_match(&entries, "", 2, true);
        assert_eq!(results.len(), 2);
        assert_eq!(results[0].path, "a.rs");
        assert_eq!(results[1].path, "b.txt");
    }

    #[test]
    fn fuzzy_match_exact() {
        let entries = vec![mk_file("src/main.rs"), mk_file("src/lib.rs")];
        let results = FileDiscovery::fuzzy_match(&entries, "main.rs", 5, true);
        assert_eq!(results.len(), 1);
        assert_eq!(results[0].path, "src/main.rs");
    }

    #[test]
    fn fuzzy_match_partial() {
        let entries = vec![mk_file("src/main.rs"), mk_file("src/lib.rs"), mk_file("Cargo.toml")];
        let results = FileDiscovery::fuzzy_match(&entries, "mnr", 5, true);
        // "mnr" fuzzy matches "main.rs" (m-a-i-n → m, n)
        assert!(!results.is_empty());
        assert!(results.iter().any(|f| f.path.contains("main")));
    }

    #[test]
    fn fuzzy_match_case_insensitive() {
        let entries = vec![mk_file("README.md"), mk_file("readme.txt")];
        let results = FileDiscovery::fuzzy_match(&entries, "readme", 5, true);
        assert_eq!(results.len(), 2);
    }

    #[test]
    fn fuzzy_match_respects_max_results() {
        let entries: Vec<FileMatch> = (0..10).map(|i| mk_file(&format!("file{i}.rs"))).collect();
        let results = FileDiscovery::fuzzy_match(&entries, "", 3, true);
        assert!(results.len() <= 3);
    }

