    #[test]
    fn fuzzy_match_slider_in_nested_path() {
        let entries = vec![
            mk_file("src/components/slider.rs"),
            mk_file("src/tui/app.rs"),
            mk_file("README.md"),
        ];
        // "slide" should match slider.rs
        let results = FileDiscovery::fuzzy_match(&entries, "slide", 10, true);
        assert_eq!(results.len(), 1);
        assert_eq!(results[0].path, "src/components/slider.rs");

        // "slider" should also match slider.rs
        let results = FileDiscovery::fuzzy_match(&entries, "slider", 10, true);
        assert_eq!(
            results.len(),
            1,
            "Expected 'slider' to match 'src/components/slider.rs', got {} results",
            results.len()
        );
        assert_eq!(results[0].path, "src/components/slider.rs");

        // "sli" should also match slider.rs (s-l-i are in order in "slider")
        let results = FileDiscovery::fuzzy_match(&entries, "sli", 10, true);
        assert_eq!(
            results.len(),
            1,
            "Expected 'sli' to match 'src/components/slider.rs', got {} results",
            results.len()
        );
        assert_eq!(results[0].path, "src/components/slider.rs");

        // "sl" should also match slider.rs
        let results = FileDiscovery::fuzzy_match(&entries, "sl", 10, true);
        assert_eq!(
            results.len(),
            1,
            "Expected 'sl' to match 'src/components/slider.rs', got {} results",
            results.len()
        );
        assert_eq!(results[0].path, "src/components/slider.rs");
    }

    // ---------------------------------------------------------------------------
    // Simulate full @ autocomplete typing flow
    // ---------------------------------------------------------------------------

    #[test]
    fn autocomplete_typing_flow_sl_then_sli() {
        // Simulate user typing @sl then continuing to @sli
        use crate::tui::autocomplete::get_query_after_char;

        let entries = vec![
            mk_file("src/components/slider.rs"),
            mk_file("src/slice_util.rs"),
            mk_file("src/tui/app.rs"),
            mk_file("README.md"),
        ];

        // Step 1: User types @ — query is empty, all files shown
        let input = "@";
        let query = get_query_after_char(input, '@');
        assert_eq!(query, "");
        let results = FileDiscovery::fuzzy_match(&entries, &query, 100, true);
        assert_eq!(results.len(), 4, "Empty query should return all files");

        // Step 2: User types s — query is "s"
        let input = "@s";
        let query = get_query_after_char(input, '@');
        assert_eq!(query, "s");
        let results = FileDiscovery::fuzzy_match(&entries, &query, 100, true);
        assert!(!results.is_empty(), "'s' should match some files");
        assert!(
            results.iter().any(|f| f.path.contains("slider")),
            "'s' should match slider.rs"
        );

        // Step 3: User types l — query is "sl"
        let input = "@sl";
        let query = get_query_after_char(input, '@');
        assert_eq!(query, "sl");
        let results = FileDiscovery::fuzzy_match(&entries, &query, 100, true);
        assert!(!results.is_empty(), "'sl' should match some files");
        assert!(
            results.iter().any(|f| f.path.contains("slider")),
            "'sl' should match slider.rs, got: {:?}",
            results.iter().map(|f| &f.path).collect::<Vec<_>>()
        );

        // Step 4: User types i — query is "sli"
        // THIS IS THE BUG: popup goes empty even though "sli" matches "slider.rs"
        let input = "@sli";
        let query = get_query_after_char(input, '@');
        assert_eq!(query, "sli");
        let results = FileDiscovery::fuzzy_match(&entries, &query, 100, true);
        assert!(
            !results.is_empty(),
            "BUG: 'sli' should match slider.rs and slice_util.rs, got {} results",
            results.len()
        );
        assert!(
            results.iter().any(|f| f.path.contains("slider")),
            "BUG: 'sli' should match slider.rs, got: {:?}",
            results.iter().map(|f| &f.path).collect::<Vec<_>>()
        );
    }

