    #[test]
    fn display_truncated_short_path_no_truncation() {
        let m = mk_file("src/main.rs");
        assert_eq!(m.display_truncated(80), "📄 src/main.rs");
    }

    #[test]
    fn display_truncated_long_path() {
        let m = mk_file("src/components/ui/widgets/slider.rs");
        let result = m.display_truncated(25);
        assert!(result.starts_with("📄"));
        assert!(result.contains("…"));
        assert!(result.ends_with("slider.rs"));
    }

    #[test]
    fn display_truncated_preserves_filename() {
        let m = mk_file("a/very/deeply/nested/path/to/some/file_name.rs");
        let result = m.display_truncated(30);
        assert!(result.ends_with("file_name.rs"));
        assert!(result.contains("…"));
    }

    #[test]
    fn display_truncated_directory_icon() {
        let m = mk_dir("src/components/ui/widgets/");
        let result = m.display_truncated(25);
        assert!(result.starts_with("📁"));
        assert!(result.contains("…"));
    }

